/**
 * Whether a query fails or returns a (possibly empty) result is observable SPARQL behavior. A failed non-silent SERVICE
 * invocation is an error for the whole query; only {@code SILENT} converts that failure into a single empty mapping.
 * Consequently an optimizer simplification or a physical short-circuit may discard a subtree unevaluated only when the
 * discarded subtree cannot raise such a query-fatal error. These witnesses use an always-failing
 * {@link FederatedService} that mirrors real vectored services (no remote request is made for an empty binding stream)
 * so that suppressed invocations are indistinguishable from never-attempted ones.
 */
public class MemoryFatalServiceErrorPreservationTest {

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new MemoryStore());
		repository.setFederatedServiceResolver(new FailingServiceResolver());
		repository.init();
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<BindingSet> evaluate(String query) {
		try (RepositoryConnection connection = repository.getConnection()) {
			return QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
		}
	}

	private boolean ask(String query) {
		try (RepositoryConnection connection = repository.getConnection()) {
			return connection.prepareBooleanQuery(query).evaluate();
		}
	}

	@Test
	public void constantFalseFilterDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> evaluate("SELECT * WHERE { SERVICE <urn:fail:1> { ?s ?p ?o } FILTER(false) }"));
	}

	@Test
	public void emptyJoinOperandDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> evaluate("SELECT * WHERE { VALUES ?x { } SERVICE <urn:fail:2> { ?s ?p ?o } }"));
	}

	@Test
	public void impossibleSameTermFilterDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> evaluate(
						"SELECT * WHERE { SERVICE <urn:fail:3> { ?s ?p ?o } FILTER(sameTerm(?neverBound, <urn:a>)) }"));
	}

	@Test
	public void optionalConstantFalseDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> evaluate(
						"SELECT * WHERE { VALUES ?x { 1 } OPTIONAL { SERVICE <urn:fail:4> { ?s ?p ?o } FILTER(false) } }"));
	}

	@Test
	public void unionWithLimitDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> evaluate(
						"SELECT * WHERE { { VALUES ?x { 1 } } UNION { SERVICE <urn:fail:5> { ?s ?p ?o } } } LIMIT 1"));
	}

	@Test
	public void askDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> ask("ASK { { VALUES ?x { 1 } } UNION { SERVICE <urn:fail:6> { ?s ?p ?o } } }"));
	}

	@Test
	public void hashJoinEmptyLeftDoesNotSuppressServiceError() {
		assertThrows(QueryEvaluationException.class,
				() -> evaluate("SELECT * WHERE { VALUES ?x { } "
						+ "{ { SERVICE <urn:fail:7> { ?s ?p ?o } } UNION { VALUES ?y { 1 } } } }"));
	}

	/** Control: a failed SILENT invocation is one empty mapping, not an error. */
	@Test
	public void silentServiceRecoversToSingleEmptyMapping() {
		List<BindingSet> rows = evaluate("SELECT * WHERE { SERVICE SILENT <urn:fail:8> { ?s ?p ?o } }");
		assertEquals(1, rows.size());
	}

	/** Control: SILENT subtrees stay freely optimizable — no error to preserve. */
	@Test
	public void silentServiceUnderConstantFalseFilterYieldsEmpty() {
		List<BindingSet> rows = evaluate(
				"SELECT * WHERE { SERVICE SILENT <urn:fail:9> { ?s ?p ?o } FILTER(false) }");
		assertEquals(0, rows.size());
	}

	private static final class FailingServiceResolver implements FederatedServiceResolver {

		@Override
		public FederatedService getService(String serviceUrl) {
			return new FailingService();
		}
	}

	/**
	 * Always-failing service. Mirrors real vectored services: {@link #evaluate} makes no "remote request" when the
	 * input binding stream is empty, and handles SILENT itself as the vectored contract requires (a failed SILENT
	 * invocation evaluates to the singleton empty mapping, so the input bindings pass through unchanged).
	 */
	private static final class FailingService implements FederatedService {

		private boolean initialized;

		@Override
		public boolean ask(Service service, BindingSet bindings, String baseUri) {
			throw new QueryEvaluationException("service unavailable");
		}

		@Override
		public CloseableIteration<BindingSet> select(Service service, Set<String> projectionVars,
				BindingSet bindings, String baseUri) {
			throw new QueryEvaluationException("service unavailable");
		}

		@Override
		public CloseableIteration<BindingSet> evaluate(Service service, CloseableIteration<BindingSet> bindings,
				String baseUri) {
			if (!bindings.hasNext()) {
				bindings.close();
				return new EmptyIteration<>();
			}
			if (service.isSilent()) {
				return bindings;
			}
			bindings.close();
			throw new QueryEvaluationException("service unavailable");
		}

		@Override
		public boolean isInitialized() {
			return initialized;
		}

		@Override
		public void initialize() {
			initialized = true;
		}

		@Override
		public void shutdown() {
			initialized = false;
		}
	}
}
